use std::error::Error;
use std::io::{self, Write};

trait StatReader {
    fn read_stats(&self) -> Result<(f32, f32), Box<dyn Error>>;
}

struct CpuStat { cpu_percent: f32 } impl StatReader for CpuStat {
    fn read_stats(&self) -> Result<(f32, f32), Box<dyn Error>> {
        Ok((self.cpu_percent, 0.0))
    }
}

struct MemStat { mem_used: f32 } impl StatReader for MemStat {
    fn read_stats(&self) -> Result<(f32, f32), Box<dyn Error>> {
        Ok((0.0, self.mem_used))
    }
}

fn monitor_system<R: StatReader>(reader: &R, interval_ms: u64) -> io::Result<()> {
    loop {
        match reader.read_stats() {
            Ok((cpu, mem)) => {
                let output = format!("CPU: {:.1}% | Memory: {:.1}%", cpu, mem);
                print!("{}", output);
                io::stdout().flush()?;
            }
            Err(e) => {
                writeln!(io::stderr(), "Error reading stats: {}", e)?; 
                break;
            }
        }
        std::thread::sleep(std::time::Duration::from_millis(interval_ms));
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let cpu_reader = CpuStat { cpu_percent: 15.5 };
    let mem_reader = MemStat { mem_used: 4096.3 };

    println!("Starting system monitor (Ctrl+C to exit)...n");

    if let Err(e) = monitor_system(&cpu_reader, 500) {
        eprintln!("Monitor stopped: {}", e);
    }

    Ok(())
}

use std::error::Error;

struct ConfigData {
    name: String,
    value: i32,
}

impl std::fmt::Display for ConfigData {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "{}: {}", self.name, self.value)
    }
}

trait Dumpable {
    fn dump_to_string(&self) -> String;
}

impl Dumpable for ConfigData {
    fn dump_to_string(&self) -> String {
        format!("{}: {}", self.name, self.value)
    }
}

fn process_data<T: Dumpable>(item: &T) -> Result<(), Box<dyn Error>> {
    println!("Processing item:");
    let s = item.dump_to_string();
    println!("Successfully dumped to string: {}", s);
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let config1 = ConfigData {
        name: String::from("database"),
        value: 500,
    };
    let config2 = ConfigData {
        name: String::from("timeout"),
        value: 30,
    };

    process_data(&config1)?;
    process_data(&config2)?;

    Ok(())
}

use std::error::Error;

struct ProofData { 
    id: u32,
    data: Vec<u8>,
}

trait Verifiable {
    fn verify_proof(&self) -> Result<(), Box<dyn Error>>;
}

impl Verifiable for ProofData {
    fn verify_proof(&self) -> Result<(), Box<dyn Error>> {
        if self.data.len() < 10 {
            return Err(format!("Proof data is too short for ID {}", self.id).into());
        }
        Ok(())
    }
}

fn process_verifiable<T: Verifiable + std::fmt::Debug>(item: &T) -> Result<(), Box<dyn Error>> {
    println!("Processing item: {:?}", item);
    item.verify_proof()?;
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let proof1 = ProofData { id: 1, data: vec![0; 20] };
    let proof2 = ProofData { id: 2, data: vec![0; 5] };

    process_verifiable(&proof1)?;
    process_verifiable(&proof2).map_err(|e| {
        println!("Caught error for ID 2: {}", e);
        e
    })?;

    Ok(())
}

use std::error::Error;
use std::fmt;

struct DataValidator {
    data: Vec<Vec<f64>>
}

impl DataValidator {
    fn new(data: Vec<Vec<f64>>) -> Self {
        DataValidator { data }
    }

    fn calculate_covariance(&self) -> Result<Vec<Vec<f64>>, Box<dyn Error>> {
        if self.data.is_empty() || self.data[0].is_empty() {
            return Err(format!("Input data cannot be empty.").into());
        }

        let num_samples = self.data.len();
        let num_features = self.data[0].len();

        if num_samples < 2 {
            return Err(format!("Need at least two samples to calculate covariance.").into());
        }

        let mut means: Vec<f64> = vec![0.0; num_features];
        for sample in &self.data {
            for j in 0..num_features {
                means[j] += sample[j];
            }
        }

        for j in 0..num_features {
            means[j] /= num_samples as f64;
        }

        let mut covariance_matrix: Vec<Vec<f64>> = vec![vec![0.0; num_features]; num_features];

        for i in 0..num_features {
            for j in 0..num_features {
                let mut sum_product = 0.0;
                for k in 0..num_samples {
                    sum_product += (self.data[k][i] - means[i]) * (self.data[k][j] - means[j]);
                }
                covariance_matrix[i][j] = sum_product / ((num_samples - 1) as f64);
            }
        }

        Ok(covariance_matrix)
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let data_set: Vec<Vec<f64>> = vec![
        vec![1.0, 2.0], 
        vec![3.0, 4.0],
        vec![5.0, 6.0]
    ];

    let validator = DataValidator::new(data_set);
    match validator.calculate_covariance() {
        Ok(cov) => {
            println!("Successfully calculated covariance matrix:");
            for row in &cov {
                print!("  [({}, {})] | ", row[0], row[1]);
            }
            println!("");
        },
        Err(e) => {
            eprintln!("Error calculating covariance: {}", e);
        }
    }

    Ok(())
}

use std::fmt::{self, Display};
use std::time::Duration;
use std::thread;

struct Task {
    name: String,
    duration: Duration,
}

trait Runnable {
    fn run(&self) -> Result<(), Box<dyn std::error::Error>>;
}

impl Display for Task {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Task: {}", self.name)
    }
}

impl Runnable for Task {
    fn run(&self) -> Result<(), Box<dyn std::error::Error>> {
        println!("Starting to process {} for {:?}", self.name, self.duration);
        thread::sleep(self.duration);
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let tasks: Vec<Box<dyn Runnable + Send>> = vec![
        Box::new(Task { name: String::from("Pomodoro Cycle"), duration: Duration::from_secs(10) }),
        Box::new(Task { name: String::from("Break Time"), duration: Duration::from_secs(5) }),
    ];

    for task in tasks.iter() {
        if let Err(e) = task.run() {
            eprintln!("Error running a task: {}", e);
        }
    }

    Ok(())
}
